const express = require('express');
const socketio = require('socket.io');
const http = require('http');

const app = express();
const server = http.createServer(app);
const io = socketio(server);

let players = {};

io.on('connection', (socket) => {
    console.log('New client connected');

    socket.on('playerAuth', (username) => {
        players[socket.id] = {
            username: username,
            score: 0
        };
        console.log(`Player ${username} authenticated`);
    });

    socket.on('playerMove', (move) => {
        // Validate player move here
    });

    socket.on('updateScore', (score) => {
        if (players[socket.id]) {
            players[socket.id].score = score;
            console.log(`Score of ${players[socket.id].username} is now ${score}`);
        }
    });

    socket.on('disconnect', () => {
        console.log(`Player ${players[socket.id].username} disconnected`);
        delete players[socket.id];
    });
});

server.listen(3000, () => {
    console.log('Server listening on port 3000');
});